+
+    // Don't forward Cmd key releases (they're handled by shortcuts)
+    if (e.metaKey) return;
+
+    // Forward keyup to active panel
+    const activePanel = muxClient?.getActivePanel();
+    if (activePanel) {
+      e.preventDefault();
+      activePanel.sendKeyInput(e, 0); // 0 = release
